/* WheelForge frontend — KLineChart view of the best premium-sell setups.
 * Reads ./data/scan.json (regenerated by ember each cycle), renders a ranked
 * list, and on select draws real candles with the short-put strike line + a
 * one-line WheelForge read. No build step. */
(function () {
  'use strict';

  var chart = null;
  var DATA = null;
  var selected = null;

  // ── interactive state (all client-side, no reload) ──────────────────────────
  var SORTS = [
    { key: 'score', label: 'score', get: function (p) { return p.score; } },
    { key: 'rich', label: 'rich', get: function (p) { return (p.factors || {}).richness || 0; } },
    { key: 'safe', label: 'safe', get: function (p) { return (p.factors || {}).safety || 0; } },
    { key: 'yield', label: 'yield', get: function (p) { return p.annualized_roc || 0; } },
    { key: 'iv', label: 'IV', get: function (p) { return p.iv || 0; } },
    { key: 'ivrank', label: 'IV-rk', get: function (p) { return p.iv_rank || 0; } },
    { key: 'support', label: 'support', get: function (p) { return p.support_floor || 0; } },
  ];
  var state = { sort: 'score', minScore: 0, minAnnual: 0, hideAvoid: false, lane: 'all', atSupport: false, maxCapital: 0, primeOnly: false };

  // ── "Prime Picks": today's standouts, the ones that compromise on NOTHING ───
  // A pick earns PRIME only when it clears all three thesis pillars at once: real
  // quality (score >= 50, a grade C or better, so the six-factor blend likes it),
  // real yield (>= 25% annualized, toward the ~100%/yr book), and real discipline
  // (>= 75% it stays OTM, so you actually keep the premium). This deliberately drops
  // a top-SCORE name with a thin 12-19% yield (safe but not a premium standout) and
  // a fat-yield speculative name the score already marked down. Relative-friendly: on
  // a weak board (no A/B grades) the C+ floor still surfaces the best honest setups.
  var PRIME = { minScore: 50, minAnnual: 25, minProbOtm: 75, max: 6 };
  function isPrime(p) {
    return !!p && !p.avoid
      && (p.score || 0) >= PRIME.minScore
      && (p.annualized_roc || 0) >= PRIME.minAnnual
      && (p.prob_otm || 0) >= PRIME.minProbOtm;
  }
  // The standouts to show in the strip: prime picks among what is currently visible,
  // best score first, capped so the band stays a short "today's standouts", not a list.
  function primeRows(rows) {
    return rows.filter(function (t) { return isPrime(t.pick); })
      .slice()
      .sort(function (a, b) { return (b.pick.score || 0) - (a.pick.score || 0); })
      .slice(0, PRIME.max);
  }

  function displayRows() {
    var s = SORTS.filter(function (x) { return x.key === state.sort; })[0] || SORTS[0];
    return (DATA.tickers || [])
      .filter(function (t) {
        var p = t && t.pick;
        if (!p) return false;  // a malformed row must never crash the board
        if (state.hideAvoid && p.avoid) return false;
        if (state.primeOnly && !isPrime(p)) return false;
        if (state.atSupport && !p.at_support) return false;
        if (state.lane !== 'all' && (p.lanes || []).indexOf(state.lane) < 0) return false;
        // Max-capital sizing: a CSP ties up strike*100 in cash collateral, so a seller with
        // a fixed per-trade budget can only actually take the picks that fit. Drop anything
        // whose collateral exceeds the cap (a pick with no strike can't be sized -> drop it).
        if (state.maxCapital > 0 && (!(p.strike > 0) || p.strike * 100 > state.maxCapital)) return false;
        if ((p.annualized_roc || 0) < state.minAnnual) return false;
        return (p.score || 0) >= state.minScore;
      })
      .slice()
      .sort(function (a, b) { return s.get(b.pick) - s.get(a.pick); });
  }

  function buildControls() {
    var host = document.getElementById('wf-controls');
    if (!host) return;
    host.innerHTML = '';
    var sortRow = document.createElement('div'); sortRow.className = 'ctl-row';
    sortRow.appendChild(label('sort'));
    SORTS.forEach(function (s) {
      var b = document.createElement('button');
      b.className = 'ctl-pill' + (state.sort === s.key ? ' on' : '');
      b.textContent = s.label;
      b.onclick = function () { state.sort = s.key; buildControls(); renderList(); };
      sortRow.appendChild(b);
    });
    host.appendChild(sortRow);
    var filtRow = document.createElement('div'); filtRow.className = 'ctl-row';
    filtRow.appendChild(label('min'));
    [0, 50, 60, 70].forEach(function (m) {
      var b = document.createElement('button');
      b.className = 'ctl-pill' + (state.minScore === m ? ' on' : '');
      b.textContent = m === 0 ? 'all' : m + '+';
      b.onclick = function () { state.minScore = m; buildControls(); renderList(); };
      filtRow.appendChild(b);
    });
    var av = document.createElement('button');
    av.className = 'ctl-pill ctl-toggle' + (state.hideAvoid ? ' on' : '');
    av.textContent = state.hideAvoid ? 'avoids hidden' : 'hide avoids';
    av.onclick = function () { state.hideAvoid = !state.hideAvoid; buildControls(); renderList(); };
    filtRow.appendChild(av);
    host.appendChild(filtRow);
    var laneRow = document.createElement('div'); laneRow.className = 'ctl-row';
    laneRow.appendChild(label('lane'));
    [['all', 'all'], ['liquid', 'liquid'], ['high_iv', 'high-IV']].forEach(function (l) {
      var b = document.createElement('button');
      b.className = 'ctl-pill' + (state.lane === l[0] ? ' on' : '');
      b.textContent = l[1];
      b.onclick = function () { state.lane = l[0]; buildControls(); renderList(); };
      laneRow.appendChild(b);
    });
    // Strike-on-support toggle: keep only picks anchored AT a major price-action floor
    // (the structural part of his thesis, sell where the market is actually holding).
    var sup = document.createElement('button');
    sup.className = 'ctl-pill ctl-floor' + (state.atSupport ? ' on' : '');
    sup.textContent = state.atSupport ? '⌂ at support' : 'at support';
    sup.onclick = function () { state.atSupport = !state.atSupport; buildControls(); renderList(); };
    laneRow.appendChild(sup);
    // Prime-only toggle: collapse the board to just today's standouts (the picks that
    // clear quality, yield, and discipline all at once). The strip above always shows
    // them; this lets him trade off only those.
    var pr = document.createElement('button');
    pr.className = 'ctl-pill ctl-prime' + (state.primeOnly ? ' on' : '');
    pr.textContent = state.primeOnly ? '★ prime only' : 'prime only';
    pr.title = 'show only Prime Picks: score 50+ (grade C+), 25%+ annualized, and 75%+ chance it stays OTM';
    pr.onclick = function () { state.primeOnly = !state.primeOnly; buildControls(); renderList(); };
    laneRow.appendChild(pr);
    host.appendChild(laneRow);
    // Yield mode: filter to the fat-premium setups that actually feed a ~100%/yr book.
    var yRow = document.createElement('div'); yRow.className = 'ctl-row';
    yRow.appendChild(label('min ann'));
    [[0, 'all'], [25, '25%+'], [50, '50%+'], [100, '100%+']].forEach(function (m) {
      var b = document.createElement('button');
      b.className = 'ctl-pill' + (state.minAnnual === m[0] ? ' on' : '');
      b.textContent = m[1];
      b.onclick = function () { state.minAnnual = m[0]; buildControls(); renderList(); };
      yRow.appendChild(b);
    });
    host.appendChild(yRow);
    // Max-capital filter: size the board to what one trade can actually tie up (strike*100
    // cash collateral). The disciplined seller sizes to capital; this turns the board into
    // only-the-picks-I-can-afford. Render-only, off the strike already in the JSON.
    var capRow = document.createElement('div'); capRow.className = 'ctl-row';
    capRow.appendChild(label('max $'));
    [[0, 'any'], [5000, '5k'], [10000, '10k'], [25000, '25k'], [50000, '50k']].forEach(function (m) {
      var b = document.createElement('button');
      b.className = 'ctl-pill' + (state.maxCapital === m[0] ? ' on' : '');
      b.textContent = m[1];
      b.onclick = function () { state.maxCapital = m[0]; buildControls(); renderList(); };
      capRow.appendChild(b);
    });
    host.appendChild(capRow);
  }
  function label(t) { var s = document.createElement('span'); s.className = 'ctl-lab'; s.textContent = t; return s; }

  function renderChanges(ch) {
    var host = document.getElementById('wf-changes');
    if (!host) return;
    if (!ch) { host.style.display = 'none'; return; }
    var parts = [];
    (ch.movers || []).forEach(function (m) {
      var up = m.delta >= 0;
      parts.push('<span class="chg ' + (up ? 'up' : 'dn') + '">' + (up ? '▲' : '▼') + esc(m.ticker)
        + ' ' + (up ? '+' : '') + esc(m.delta) + '</span>');
    });
    if ((ch.new || []).length) parts.push('<span class="chg new">new ' + esc(ch.new.join(' ')) + '</span>');
    if ((ch.to_avoid || []).length) parts.push('<span class="chg avoid">→ AVOID ' + esc(ch.to_avoid.join(' ')) + '</span>');
    if ((ch.from_avoid || []).length) parts.push('<span class="chg ok">cleared ' + esc(ch.from_avoid.join(' ')) + '</span>');
    host.style.display = '';
    host.innerHTML = '<span class="chg-lab">since last scan</span> '
      + (parts.length ? parts.join('   ') : '<span class="chg">no changes</span>');
  }

  // The letter grade reads the board at a glance. Use the score the engine baked in
  // (p.grade) when present; fall back to the same bands client-side so the page still
  // grades correctly on a scan.json built before the engine carried the field.
  function gradeFor(p) {
    if (p && p.grade) return p.grade;
    var s = p ? p.score : 0;
    if (p && p.avoid) return 'F';
    if (s >= 80) return 'A';
    if (s >= 65) return 'B';
    if (s >= 50) return 'C';
    if (s >= 35) return 'D';
    return 'F';
  }

  function heatColor(score) {
    // cold steel -> ember -> amber -> white hot
    if (score >= 80) return '#fff1c2';
    if (score >= 70) return '#ffb000';
    if (score >= 60) return '#ff7a18';
    if (score >= 45) return '#d65a3a';
    return '#5c6b73';
  }

  // A hex level color -> translucent rgba, so a filled zone reads UNDER the
  // walls and candles instead of painting over them.
  function hexToRgba(hex, a) {
    var h = String(hex || '').replace('#', '');
    if (h.length === 3) h = h[0] + h[0] + h[1] + h[1] + h[2] + h[2];
    if (h.length !== 6) return 'rgba(120,200,255,' + a + ')';
    return 'rgba(' + parseInt(h.substr(0, 2), 16) + ',' + parseInt(h.substr(2, 2), 16)
      + ',' + parseInt(h.substr(4, 2), 16) + ',' + a + ')';
  }

  // A full-width translucent band between two price levels. Michael's ask: SHADE
  // the put-sell zone (not just lines) and tint it by score. One register, reused
  // for every pick; the fill color rides in via extendData so a single overlay
  // template serves all scores (and, later, the call-sell zone above price).
  var zoneRegistered = false;
  function registerZoneBand() {
    if (zoneRegistered) return;
    zoneRegistered = true;
    klinecharts.registerOverlay({
      name: 'zoneBand',
      totalStep: 2,
      needDefaultPointFigure: false,
      needDefaultXAxisFigure: false,
      needDefaultYAxisFigure: false,
      createPointFigures: function (o) {
        var cs = o.coordinates || [];
        if (cs.length < 2 || cs[0].y == null || cs[1].y == null) return [];
        var top = Math.min(cs[0].y, cs[1].y), bot = Math.max(cs[0].y, cs[1].y);
        var w = (o.bounding && o.bounding.width) || 0;
        var color = (o.overlay && o.overlay.extendData && o.overlay.extendData.color)
          || 'rgba(120,200,255,0.10)';
        return [{
          type: 'polygon', ignoreEvent: true,
          attrs: { coordinates: [ { x: 0, y: top }, { x: w, y: top }, { x: w, y: bot }, { x: 0, y: bot } ] },
          styles: { style: 'fill', color: color }
        }];
      }
    });
  }

  function chartStyles() {
    return {
      grid: { horizontal: { color: '#161c27' }, vertical: { color: '#161c27' } },
      candle: {
        bar: {
          upColor: '#26d07c', downColor: '#ff5b6e', noChangeColor: '#8b97a8',
          upBorderColor: '#26d07c', downBorderColor: '#ff5b6e', noChangeBorderColor: '#8b97a8',
          upWickColor: '#26d07c', downWickColor: '#ff5b6e', noChangeWickColor: '#8b97a8'
        },
        priceMark: {
          high: { color: '#8b97a8' }, low: { color: '#8b97a8' },
          last: { line: { color: '#ffb000' }, text: { color: '#07090e', backgroundColor: '#ffb000' } }
        },
        tooltip: { text: { color: '#e7edf5' } }
      },
      xAxis: { axisLine: { color: '#2a3140' }, tickText: { color: '#8b97a8' }, tickLine: { color: '#2a3140' } },
      yAxis: { axisLine: { color: '#2a3140' }, tickText: { color: '#8b97a8' }, tickLine: { color: '#2a3140' } },
      crosshair: { horizontal: { line: { color: '#3a4456' }, text: { backgroundColor: '#1a212e' } },
                   vertical: { line: { color: '#3a4456' }, text: { backgroundColor: '#1a212e' } } }
    };
  }

  function fmt(n) { return (n == null) ? '-' : Number(n).toLocaleString(undefined, { maximumFractionDigits: 2 }); }
  // His pre-order screen is per-WEEK ("did I sell for at least 1% this week?"), not the
  // annualized math. Prefer the baked weekly_yield_pct; until the box rebuilds, fall back to
  // the simple inverse of the annualized RoC (ann / 52) so the card reads right immediately.
  // Same client-fallback discipline as gradeFor(): the page never waits on a scan rebuild.
  function weeklyPct(p) {
    if (!p) return null;
    if (p.weekly_yield_pct != null) return Number(p.weekly_yield_pct);
    if (p.annualized_roc != null) return Math.round(Number(p.annualized_roc) / 52 * 100) / 100;
    return null;
  }
  // Escape text bound into HTML (attributes/innerHTML). Modest first step on the open
  // robustness item; used here so the factor tooltips never break a title attribute.
  function esc(s) {
    return String(s == null ? '' : s)
      .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
  }
  function fmtDate(iso) {
    if (!iso) return '';
    try { return new Date(iso + 'T00:00:00').toLocaleDateString(undefined, { month: 'short', day: 'numeric' }); }
    catch (e) { return ''; }
  }

  // The score is a blend; show the bar-by-bar why behind it. Order matches the
  // thesis: rich + safe + yield lead (sell dear, stay disciplined, hit the number).
  var FAC = { richness: 'rich', safety: 'safe', yield: 'yield', free_shares: 'shares', liquidity: 'liq', structure: 'struct' };
  // What each bar actually MEANS. The page showed six bars and a 0-100 with no legend;
  // these are the plain-English tooltips so anyone (incl. Michael at a glance) can read
  // WHY a pick scores, not just that it does. Wording tracks GOAL's factor definitions.
  var FAC_HELP = {
    richness: 'rich: how dear the premium is. Implied vol vs the stock\'s realized vol (VRP). Higher = you are paid more than the name actually moves. This is the edge.',
    safety: 'safe: probability the put expires out of the money (you keep the premium, no assignment). Higher = more disciplined, less likely to be put the shares.',
    yield: 'yield: annualized return on the cash collateral if it expires worthless. Higher = closer to the ~100%/yr income target.',
    free_shares: 'shares: wheel-fit. If you ARE assigned, do you end up owning a name you want at a basis you like. Low on a name you only sold for premium.',
    liquidity: 'liq: how tradeable it is. Bid/ask spread tightness and open interest. Higher = an edge you can actually fill, not a paper quote.',
    structure: 'struct: where price sits vs its Keltner channel and support. Higher = holding structure, not selling puts into a falling knife.'
  };
  // Strip the leading "rich: " label off a FAC_HELP string so it can sit after a
  // bolded factor name without repeating it.
  function stripLead(s) { s = String(s == null ? '' : s); var i = s.indexOf(': '); return i >= 0 ? s.slice(i + 2) : s; }

  // A plain-English "how scoring works" panel. The page showed six bars and a 0-100
  // with no legend; this says what the numbers MEAN and how a pick is chosen, for a
  // first-time viewer (and Michael at a glance). Static and collapsed by default; it
  // reuses the SAME FAC_HELP wording as the per-bar tooltips so the two never drift.
  function renderHowItWorks() {
    var host = document.getElementById('wf-how-body');
    if (!host) return;
    var facs = Object.keys(FAC).map(function (k) {
      return '<li><b>' + esc(FAC[k]) + '</b> &mdash; ' + esc(stripLead(FAC_HELP[k])) + '</li>';
    }).join('');
    host.innerHTML =
      '<p>Every setup earns a <b>Premium Quality Score</b> (0-100) and a letter grade, '
      + 'blended from six factors. The thesis leads: sell <b>rich</b> premium, stay '
      + '<b>safe</b>, hit the <b>yield</b>, and only get assigned names you actually want.</p>'
      + '<ul class="how-facs">' + facs + '</ul>'
      + '<p class="how-veto"><b>Earnings before expiry is a hard AVOID</b> &mdash; a veto, '
      + 'not a factor. WheelForge never sells a put through an earnings print.</p>'
      + '<p>Grades band the score: <b>A</b> 80+, <b>B</b> 65+, <b>C</b> 50+, <b>D</b> 35+, '
      + '<b>F</b> below (an AVOID is an honest F). Two lanes split the universe: <b>liquid</b> '
      + 'ownable staples and a <b>high-IV</b> richness screen.</p>';
  }

  // Same ramp the engine uses for the yield factor (8% floor, ~100% maxes it), so
  // the bar reads live off annualized_roc even before the box rebuilds the factors.
  function yieldFrac(p) {
    var roc = (Number(p.annualized_roc) || 0) / 100.0;  // stored as a percent
    return Math.max(0, Math.min(1, (roc - 0.08) / (1.0 - 0.08)));
  }
  function factorBars(p) {
    var f = (p && p.factors) || {};
    var html = '<span class="facwrap">';
    Object.keys(FAC).forEach(function (k) {
      var raw = (k === 'yield' && f.yield == null) ? yieldFrac(p) : (Number(f[k]) || 0);
      var v = Math.round(raw * 100);
      // No live chain means IV was assumed at 1.15x realized vol, so the richness bar
      // is modeled not measured. Dim it and flag it rather than passing it off as real.
      var assumed = (k === 'richness' && p.vrp_assumed);
      var lab = FAC[k] + (assumed
        ? '<span class="ivproxy" title="no live option chain: IV assumed at 1.15x realized vol, so this richness is modeled, not measured">~</span>'
        : '');
      // Hovering the factor (label or bar) explains what it means and shows this pick's value.
      var help = esc((FAC_HELP[k] || FAC[k]) + '  (' + v + '/100)');
      html += '<span class="fac' + (assumed ? ' fac-assumed' : '') + '" title="' + help + '"><span class="faclab">' + lab + '</span>'
        + '<span class="facbar"><span class="facfill" style="width:' + v + '%;background:'
        + heatColor(v) + '"></span></span></span>';
    });
    return html + '</span>';
  }

  // The yield ladder: the other candidate weeklies at the same support strike, ranked by
  // annualized RoC. The winner (the tenor we actually quote) is lit; the rest show what
  // you give up. Makes the "a bi-weekly sometimes pays ~2x for trivially more risk"
  // comparison visible instead of silently committing to the nearest weekly.
  function dteLadder(p) {
    var L = p && p.dte_ladder;
    if (!L || L.length < 2) return '';
    var rungs = L.map(function (q) {
      var on = (q.dte === p.dte);
      return '<span class="rung' + (on ? ' on' : '') + '" title="$' + fmt(q.strike)
        + ' put, prem $' + fmt(q.premium) + '">' + q.dte + 'd <b>' + fmt(q.ann_roc) + '%</b></span>';
    }).join(' ');
    return '<div class="dte-ladder"><span class="dl-lab">yield ladder</span> ' + rungs + '</div>';
  }

  // The "Prime Picks" strip: a short, highlighted best-of band ABOVE the full list,
  // the page's "today's standouts". Render-only off fields already in the JSON; it
  // mirrors the current filters (computed from the visible rows) so the strip never
  // names a pick the board below isn't showing. Hidden entirely when nothing qualifies
  // (an honest "no standouts today" rather than an empty box).
  function renderPrime(rows) {
    var host = document.getElementById('wf-prime');
    if (!host) return;
    var prime = primeRows(rows);
    if (!prime.length) { host.style.display = 'none'; host.innerHTML = ''; return; }
    host.style.display = '';
    var chips = prime.map(function (t) {
      var p = t.pick, g = gradeFor(p);
      return '<button class="prime-chip" data-ticker="' + esc(t.ticker)
        + '" title="' + esc(t.ticker + ': grade ' + g + ', ' + fmt(p.annualized_roc)
          + '% annualized, ' + fmt(p.prob_otm) + '% stays OTM') + '">'
        + '<span class="pc-grade grade-' + g + '">' + g + '</span> '
        + '<b>' + esc(t.ticker) + '</b> '
        + '<span class="pc-ann">' + Math.round(Number(p.annualized_roc)) + '%</span></button>';
    }).join('');
    host.innerHTML = '<span class="prime-lab" title="today\'s standouts: picks that clear quality '
      + '(score 50+, grade C+), yield (25%+ annualized), and discipline (75%+ stays OTM) all at once">'
      + '★ prime picks</span> ' + chips;
    Array.prototype.forEach.call(host.querySelectorAll('.prime-chip'), function (b) {
      b.onclick = function () { select(b.getAttribute('data-ticker')); };
    });
  }

  function renderList() {
    var host = document.getElementById('wf-cards');
    host.innerHTML = '';
    var rows = displayRows();
    renderPrime(rows);
    if (!rows.length) { host.innerHTML = '<div class="ctl-empty">nothing clears that filter</div>'; return; }
    rows.forEach(function (t, i) {
      var p = t.pick;
      if (!p) return;  // displayRows already drops these, but never deref a null pick
      var card = document.createElement('div');
      var isTop = (i === 0 && !p.avoid);
      var prime = isPrime(p);
      card.className = 'wf-card' + (i === 0 ? ' is-sel' : '') + (isTop ? ' is-top' : '')
        + (prime ? ' is-prime' : '') + (p.avoid ? ' is-avoid' : '');
      card.dataset.ticker = t.ticker;
      var sc = document.createElement('div');
      sc.className = 'wf-score';
      var col = p.avoid ? '#ff5b6e' : heatColor(p.score);
      sc.style.borderColor = col;
      sc.style.boxShadow = '0 0 16px ' + col + '33';
      // The letter grade leads INSIDE the score tile and the raw number confirms below it,
      // so the board reads A/B/C at a glance before the eye decodes a single digit (c47).
      // The c41 grade used to float in the card's top-left padding dead-zone; this lands it.
      var gl = gradeFor(p);
      var gr = document.createElement('div');
      gr.className = 'wf-grade grade-' + gl;
      gr.textContent = gl;
      gr.title = 'grade ' + gl + ' (A>=80 B>=65 C>=50 D>=35 F below; an AVOID is an honest F)';
      // Under the grade letter the tile confirms the number Michael actually trades off:
      // annualized yield, not the raw 0-100 score (the grade already bands that). The raw
      // score moves to the tooltip so it is still one hover away (product critic 06-27 19:46Z).
      var num = document.createElement('div');
      num.className = 'wf-num';
      if (p.avoid) {
        num.textContent = '✕'; num.style.color = col;
      } else {
        num.classList.add('yield');
        num.textContent = (p.annualized_roc != null) ? Math.round(Number(p.annualized_roc)) + '%' : '-';
        num.title = 'Premium Quality Score ' + p.score + '/100 (the grade letter above bands it)';
      }
      sc.appendChild(gr); sc.appendChild(num);
      // The top-ranked pick announces itself: a TOP badge on the score tile so his eye
      // lands before he reads a single digit. Anchored to rank, independent of selection.
      if (isTop) {
        var tb = document.createElement('div');
        tb.className = 'wf-topbadge'; tb.textContent = 'TOP';
        tb.title = 'highest-ranked pick under the current sort and filters';
        sc.appendChild(tb);
      }
      var tk = document.createElement('div'); tk.className = 'wf-tk'; tk.textContent = t.ticker;
      var dir = document.createElement('div'); dir.className = 'wf-dir'; dir.textContent = p.direction;
      // The #1 pick gets its actual trade as a bold amber HEADLINE, not buried in the dense
      // sub-line: SELL $STRIKE PUT · DATE · ANN%/yr reads in one second from arm's length
      // (the TOP badge alone is a 9px chip nobody can read across the room). Top-only so it
      // stays a single anchor, never noise on every card (product critic 06-29 07:46Z).
      var head = null;
      if (isTop) {
        head = document.createElement('div');
        head.className = 'wf-topline';
        var leg = (p.direction && /call/i.test(p.direction)) ? ' CALL' : ' PUT';
        // Splice the dollar premium between the date and the yield so the headline is a
        // COMPLETE trade ticket: the cash collected per contract is the number he types into
        // the order, not the annualized math (product critic 06-30 01:48Z). Null-guard it so a
        // pre-bake row with no premium just omits that segment, never prints "$-".
        head.textContent = 'SELL $' + fmt(p.strike) + leg
          + (p.exp ? ' · ' + fmtDate(p.exp) : '')
          + (p.premium != null ? ' · $' + fmt(p.premium) : '')
          + (p.annualized_roc != null ? ' · ' + Math.round(Number(p.annualized_roc)) + '%/yr' : '');
        head.title = 'the top-ranked trade, as a headline: strike, expiry, premium per contract, and annualized yield';
      }
      var sub = document.createElement('div'); sub.className = 'wf-sub';
      if (p.avoid) {
        sub.innerHTML = '<b class="avoidtxt">AVOID</b> earnings in <b>'
          + (p.earnings_days != null ? p.earnings_days + 'd' : 'window') + '</b> before expiry';
      } else {
        var src = (p.source === 'live')
          ? '<span class="src live">LIVE</span>' : '<span class="src model">MODEL</span>';
        var hiv = ((p.lanes || []).indexOf('high_iv') >= 0) ? ' <span class="src hiv">HI-IV</span>' : '';
        var otm = (p.strike_pct_otm != null)
          ? ' <span class="otm">~' + fmt(p.strike_pct_otm) + '% OTM</span>' : '';
        // Floor badge: the strike sits on a major support level he can sell into. Show the
        // floor PRICE ($383) so he sees WHERE the support is, not just that there is one; the
        // touch count (x7) tells a real floor from a stale one-off pivot at a glance.
        var floor = p.at_support
          ? ' <span class="floor" title="strike anchored at major price-action support (floor strength '
            + (p.support_floor != null ? p.support_floor : '?')
            + (p.support_touches != null ? '; tested ' + p.support_touches + ' times' : '')
            + ')">⌂ support'
            + (p.support != null ? ' $' + fmt(p.support) : '')
            + (p.support_touches != null ? ' x' + p.support_touches : '')
            + '</span>' : '';
        // Capital-concentration chip: a fine setup that doubles up a sector already owned by a
        // higher-ranked pick. Correlated exposure WheelForge used to miss; now he sizes or skips
        // it on purpose. Server sets sector_crowded over the full ranked universe.
        var crowd = p.sector_crowded
          ? ' <span class="crowd" title="' + esc(p.sector || 'this sector')
            + ' is already represented by a higher-ranked pick: correlated exposure, so size it down or skip it on purpose">⚠ '
            + esc(p.sector ? String(p.sector).toUpperCase().slice(0, 4) : 'SECTOR') + '</span>' : '';
        // Strike-level liquidity caution: the support-anchored strike landed on a thin open-
        // interest line. It fills, but slow and wide, so he sizes down or skips on purpose. Server
        // flags thin_oi on the LIVE path only (modeled picks carry oi=0 and already say MODEL).
        var thin = p.thin_oi
          ? ' <span class="thin" title="the chosen strike sits on a thin open-interest line: it fills, but slow and at a wider spread, so size down or skip it on purpose">⚠ thin OI</span>'
          : '';
        // Free-shares fit on the card face: if this is a name he WANTS to own and assignment
        // would land an effective cost basis (strike - premium) below today's price, that
        // discount IS the thesis (own it cheap, not just rent the premium). It lived only
        // behind the expand; surface "own N% below" where the buy/skip call is actually made.
        // Gated on want_to_own AND a positive discount on purpose: on a high-IV name he sold
        // purely for premium (want_to_own false, c54), assignment is the RISK not the reward,
        // so pitching a cheap basis there would lie. The pre-bake guard keeps old scans clean.
        var disc = (p.want_to_own && p.free_shares && p.free_shares.basis_discount_pct > 0)
          ? p.free_shares.basis_discount_pct : null;
        var basis = (disc != null)
          ? ' <span class="basis" title="free-shares fit: if assigned, your effective cost basis (strike minus premium) is '
            + fmt(disc) + '% below today’s price. On a name you want to own, that discount is the win, not a risk.">↓ own '
            + fmt(disc) + '% below</span>'
          : '';
        // Earnings could not be confirmed: neither the screener feed nor the yfinance re-lookup
        // returned a date, so the hard earnings AVOID gate had nothing to fire on. The pick is
        // NOT vetoed (we can't fail-closed without blanking the board on a flaky feed), so warn
        // that the coast is unconfirmed rather than silently assuming it is clear (cycle 78).
        var earnUnk = p.earnings_unknown
          ? ' <span class="earnunk" title="could not confirm this name is clear of an earnings print: no earnings date from the screener or the yfinance lookup, so the hard AVOID gate could not check it. Verify before selling.">⚠ earnings unknown</span>'
          : '';
        // Prime marker: this one card cleared all three thesis pillars (quality + yield +
        // discipline). Same set the strip above names; flagged here too so it's identifiable
        // when scrolling the full board.
        var primeChip = prime
          ? ' <span class="prime" title="prime pick: clears quality (grade C+), yield (25%+ annualized), and discipline (75%+ stays OTM) all at once">★ prime</span>'
          : '';
        sub.innerHTML = 'sell <b>$' + fmt(p.strike) + ' put</b>' + otm + floor + basis
          + (p.exp ? ' &middot; exp <b>' + fmtDate(p.exp) + '</b> (' + p.dte + 'd)' : ' (' + p.dte + 'd)')
          + '<br><b>' + fmt(p.annualized_roc) + '%</b> ann'
          + ((weeklyPct(p) != null) ? ' <span class="wk" title="yield per week, his pre-order screen: ann RoC / 52. Aim for ~1%/wk toward the 100%/yr book.">(' + fmt(weeklyPct(p)) + '%/wk)</span>' : '')
          + ' &middot; <b>' + fmt(p.prob_otm) + '%</b> OTM '
          + src + hiv + crowd + thin + earnUnk + primeChip + (p.earnings_days != null ? ' &middot; earn ' + p.earnings_days + 'd' : '');
      }
      card.appendChild(sc); card.appendChild(tk); card.appendChild(dir);
      if (head) card.appendChild(head);
      card.appendChild(sub);
      // The plain-English "why this score" rides the card itself, not just the readout you
      // have to click into. The numbers say WHAT; this one line says WHY in his own terms
      // (rich premium, safe distance, fat yield, ...). Non-avoid only; an AVOID card already
      // leads with its veto reason, so a second why-line would just be noise (c70).
      if (!p.avoid && p.why) {
        var why = document.createElement('div');
        why.className = 'wf-why';
        why.textContent = p.why;
        card.appendChild(why);
      }
      card.addEventListener('click', function () { select(t.ticker); });
      host.appendChild(card);
    });
  }

  function select(ticker) {
    var t = (DATA.tickers || []).find(function (x) { return x.ticker === ticker; });
    if (!t || !t.pick) return;  // never render a readout off a missing pick
    selected = ticker;
    document.querySelectorAll('.wf-card').forEach(function (c) {
      c.classList.toggle('is-sel', c.dataset.ticker === ticker);
    });
    var p = t.pick;
    var srcTag = (p.source === 'live') ? '<span class="src live">LIVE chain</span>'
                                       : '<span class="src model">MODELED</span>';
    var earn = (p.avoid)
      ? ' · <span class="avoidtxt">AVOID earnings in ' + p.earnings_days + 'd</span>'
      : (p.earnings_days != null ? ' · earnings ' + p.earnings_days + 'd out' : '');
    document.getElementById('wf-readout').innerHTML =
      '<span class="k">' + esc(t.ticker) + '</span> spot ' + fmt(t.spot)
      + ' · sell the <span class="k">$' + fmt(p.strike) + ' put</span>'
      + (p.exp ? ' expiring <span class="k">' + fmtDate(p.exp) + '</span> (' + p.dte + ' DTE) ' : ' (' + p.dte + ' DTE) ') + srcTag
      + ' · prem <span class="k">$' + fmt(p.premium) + '</span>'
      + ' · <span class="k">' + fmt(p.annualized_roc) + '%</span> annualized'
      + ((p.bid_ann_roc != null && p.bid_ann_roc < p.annualized_roc)
          ? ' <span class="ivproxy" title="the headline is priced on the mid; you sell-to-open into the bid, so this is the yield that actually hits the account">(' + fmt(p.bid_ann_roc) + '% on the bid)</span>'
          : '')
      + ' · <span class="k">' + fmt(p.prob_otm) + '%</span> stays OTM'
      + '<span class="ivproxy" title="risk-neutral N(d2); real-world odds run a bit higher on names with positive drift">*</span>'
      + ' · IV ' + fmt(p.iv) + '%'
      + (p.vrp_assumed
          ? '<span class="ivproxy" title="no live option chain: IV assumed at 1.15x realized vol, so VRP/richness here is modeled, not traded">~assumed</span>'
          : '')
      + (p.iv_rank != null
          ? ' · ' + (p.iv_rank_real
                ? 'IV-rank'
                : '<span class="ivproxy" title="realized-vol proxy until the IV-history store fills; not true implied-vol rank yet">rv-rank</span>')
            + ' <span class="k">' + fmt(p.iv_rank) + '</span>'
          : '')
      + earn
      + ' · <span class="why">' + esc(p.why) + '</span>'
      + factorBars(p)
      + dteLadder(p)
      + (p.free_shares
          ? '<div class="fs-line"><span class="fs-badge" style="color:'
            + heatColor(p.free_shares.wheel_fit) + ';border-color:' + heatColor(p.free_shares.wheel_fit)
            + '">WHEEL-FIT ' + p.free_shares.wheel_fit + '</span> '
            + '<span class="fs-sum">' + esc(p.free_shares.summary) + '</span></div>'
          : '')
      + '<div class="chart-key">chart lines: '
        + '<b style="color:' + heatColor(p.score) + '">shaded put-sell zone</b> (spot to strike, by score) &nbsp;·&nbsp; '
        + '<b style="color:#22d3ee">major S/R</b> (price action) &nbsp;·&nbsp; '
        + '<b style="color:#26d07c">support</b>/<b style="color:#ff7a18">resistance</b> walls (volatility) &nbsp;·&nbsp; '
        + '<span style="color:#8b97a8">20d avg</span> &nbsp;·&nbsp; '
        + '<b style="color:' + heatColor(p.score) + '">your $' + fmt(p.strike) + ' strike</b></div>';

    if (!t.candles || !t.candles.length) return;
    chart.applyNewData(t.candles);
    chart.removeOverlay();
    drawLevels(p, t.spot);
  }

  // Draw the levels prominently: Keltner walls (resistance/support), the SMA
  // midline, and the put strike in heat. The Keltner bands are the support/
  // resistance walls she computes for the structure factor.
  function hline(value, color, dashed, size) {
    if (value == null || !isFinite(value)) return;
    chart.createOverlay({
      name: 'priceLine', points: [{ value: value }], lock: true,
      styles: { line: { color: color, style: dashed ? 'dashed' : 'solid', size: size || 1 },
                text: { color: '#07090e', backgroundColor: color } }
    });
  }
  function drawLevels(p, spot) {
    var lv = p.levels || {}, kc = lv.keltner || {};
    // The PUT-SELL ZONE, shaded: the cushion from spot down to your strike. A
    // filled translucent band tinted by score (greener-hot = a better setup,
    // steel = thin), so the buffer reads at a glance, not just as two lines. Sits
    // UNDER the walls (drawn next) and the candles. Guarded: only a real CSP
    // cushion (spot strictly above the strike) gets a band.
    if (spot != null && isFinite(spot) && p.strike != null && spot > p.strike) {
      chart.createOverlay({
        name: 'zoneBand', lock: true,
        extendData: { color: hexToRgba(heatColor(p.score), 0.13) },
        points: [{ value: spot }, { value: p.strike }]
      });
    }
    // Keltner VOLATILITY walls (thin).
    hline(kc.upper, '#ff7a18', false, 1);   // resistance wall (hot)
    hline(kc.sma, '#5c6b73', true, 1);      // 20d midline
    hline(kc.lower, '#26d07c', false, 1);   // support wall
    // Major PRICE-ACTION support / resistance (cyan, thicker = "major").
    hline(lv.resistance, '#22d3ee', false, 2);
    hline(lv.support, '#22d3ee', false, 2);
    // The strike, prominent.
    hline(p.strike, heatColor(p.score), false, 2);
  }

  // Paint a freshly fetched scan. Keeps the viewer where they were: same sort/
  // filter state, and the same selected ticker if it survived the rescan;
  // otherwise lands on the top-ranked pick (not raw ticker[0], which was AAL).
  function applyData(d) {
    DATA = d;
    document.getElementById('wf-meta').textContent = 'updated ' + (d.generated_at || '') + ' UTC';
    document.getElementById('wf-foot').textContent = d.source_note || '';
    renderChanges(d.changes);
    buildControls();
    renderList();
    var rows = displayRows();
    var keep = selected && (DATA.tickers || []).some(function (t) { return t.ticker === selected; });
    if (keep) select(selected);
    else if (rows.length) select(rows[0].ticker);
  }

  // ember reships scan.json every cycle; an open tab should follow her without a
  // manual reload. Poll on an interval and whenever the tab regains focus, and
  // only repaint when the scan timestamp actually moved.
  var POLL_MS = 120000;
  function loadData(isInitial) {
    return fetch('./data/scan.json?t=' + Date.now())
      .then(function (r) { return r.json(); })
      .then(function (d) {
        if (!isInitial && DATA && d.generated_at === DATA.generated_at) return;
        applyData(d);
      })
      .catch(function (e) {
        if (isInitial && !DATA) {
          document.getElementById('wf-readout').textContent = 'no scan data yet (' + e + ')';
        }
      });
  }

  function boot() {
    registerZoneBand();
    chart = klinecharts.init('wf-chart', { styles: chartStyles() });
    renderHowItWorks();
    loadData(true);
    setInterval(function () { loadData(false); }, POLL_MS);
    document.addEventListener('visibilitychange', function () {
      if (!document.hidden) loadData(false);
    });
    window.addEventListener('resize', function () { if (chart) chart.resize(); });
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
})();
